#include <bits/stdc++.h>
using namespace std;
struct Node{
    int x,y,e;
}c[100005];
int num[200005],sum,f[200005];
map<int,int> id;
int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx;
}
bool cmp(Node i,Node j){
    return i.e>j.e;
}
int main(){
    int t,n;
    scanf("%d",&t);
    while(t--){
        sum=0;
        map<int,bool> use;
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d%d%d",&c[i].x,&c[i].y,&c[i].e);
            if(!use[c[i].x])
                use[c[i].x]=1,num[++sum]=c[i].x;
            if(!use[c[i].y])
                use[c[i].y]=1,num[++sum]=c[i].y;
        }
        sort(c+1,c+n+1,cmp);
        sort(num+1,num+sum+1);
        for(int i=1;i<=sum;i++)
            id[num[i]]=i;
        for(int i=1;i<=sum;i++)
            f[i]=i;
        bool flag=true;
        for(int i=1;i<=n;i++){
            if(c[i].e)
                merge(id[c[i].x],id[c[i].y]);
            else
                if(father(id[c[i].x])==father(id[c[i].y])){
                    flag=false;
                    break;
                }
        }
        if(flag)
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}
